+  onFinalize?: (result: ChannelTurnResult) => Promise<void> | void;
+};
+
+export type RunChannelTurnParams<TRaw> = {
+  channel: string;
+  accountId?: string;
+  raw: TRaw;
+  adapter: ChannelTurnAdapter<TRaw>;
+  log?: (event: ChannelTurnLogEvent) => void;
+};

